int minSwaps(String s) {
    int zeros = 0, ones = 0;
    for (char c : s.toCharArray()) {
        if (c == '0') {
            zeros++;
        } else {
            ones++;
        }
    }

    if (Math.abs(zeros - ones) > 1) {
        return -1;
    }

    int mismatchCount1 = 0, mismatchCount2 = 0;
    for (int i = 0; i < s.length(); i++) {
        if (i % 2 == 0) {
            if (s.charAt(i) != '0') mismatchCount1++;
            if (s.charAt(i) != '1') mismatchCount2++;
        } else {
            if (s.charAt(i) != '1') mismatchCount1++;
            if (s.charAt(i) != '0') mismatchCount2++;
        }
    }

    return Math.min(mismatchCount1, mismatchCount2) / 2;
}
